using System.ComponentModel.DataAnnotations;

namespace sv_bfe9cc4b7a214c19bfa9078cce460f6b.Models;

public class Product
{
    public int Id { get; set; }

    [Required(ErrorMessage = "Name is required.")]
    public string Name { get; set; } = string.Empty;

    [Range(0, 9999, ErrorMessage = "Quantity must be between 0 and 9999.")]
    public int Quantity { get; set; }

    [Range(0.01, double.MaxValue, ErrorMessage = "Unit price must be greater than 0.")]
    public decimal UnitPrice { get; set; }

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;

    public static readonly string[] Categories = { "Electronics", "Clothing", "Food", "Other" };
}

using sv_bfe9cc4b7a214c19bfa9078cce460f6b.Models;

namespace sv_bfe9cc4b7a214c19bfa9078cce460f6b.Services;

public class InventoryService
{
    private readonly List<Product> _products = new()
    {
        new Product { Id = 1, Name = "Laptop",        Quantity = 25,  UnitPrice = 999.99m,  Category = "Electronics" },
        new Product { Id = 2, Name = "T-Shirt",       Quantity = 150, UnitPrice = 19.99m,   Category = "Clothing" },
        new Product { Id = 3, Name = "Organic Apples", Quantity = 300, UnitPrice = 3.49m,   Category = "Food" },
        new Product { Id = 4, Name = "Wireless Mouse", Quantity = 80,  UnitPrice = 24.95m,  Category = "Electronics" },
        new Product { Id = 5, Name = "Winter Jacket",  Quantity = 40,  UnitPrice = 89.50m,  Category = "Clothing" },
        new Product { Id = 6, Name = "Coffee Beans",   Quantity = 200, UnitPrice = 12.99m,  Category = "Food" },
    };

    private readonly Lock _lock = new();

    public Task<List<Product>> GetAllAsync()
    {
        lock (_lock)
        {
            var copy = _products.Select(p => new Product
            {
                Id = p.Id,
                Name = p.Name,
                Quantity = p.Quantity,
                UnitPrice = p.UnitPrice,
                Category = p.Category
            }).ToList();

            return Task.FromResult(copy);
        }
    }

    public Task UpdateAsync(Product updated)
    {
        lock (_lock)
        {
            var existing = _products.FirstOrDefault(p => p.Id == updated.Id)
                ?? throw new InvalidOperationException($"Product with Id {updated.Id} not found.");

            existing.Name = updated.Name;
            existing.Quantity = updated.Quantity;
            existing.UnitPrice = updated.UnitPrice;
            existing.Category = updated.Category;
        }

        return Task.CompletedTask;
    }
}

@page "/inventory"
@rendermode InteractiveServer
@using sv_bfe9cc4b7a214c19bfa9078cce460f6b.Models
@using sv_bfe9cc4b7a214c19bfa9078cce460f6b.Services
@inject InventoryService InventoryService

<PageTitle>Inventory</PageTitle>

<h1>Inventory</h1>

@if (_products is null)
{
    <p><em>Loading...</em></p>
}
else
{
    <table class="table">
        <thead>
            <tr>
                <th>Name</th>
                <th>Quantity</th>
                <th>Unit Price</th>
                <th>Category</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var product in _products)
            {
                @if (_editingId == product.Id)
                {
                    <tr>
                        <td>
                            <input class="form-control" @bind="_editModel!.Name" />
                            @if (_validationErrors.TryGetValue(nameof(Product.Name), out var nameErr))
                            {
                                <div class="text-danger small">@nameErr</div>
                            }
                        </td>
                        <td>
                            <input type="number" class="form-control" @bind="_editModel!.Quantity" />
                            @if (_validationErrors.TryGetValue(nameof(Product.Quantity), out var qtyErr))
                            {
                                <div class="text-danger small">@qtyErr</div>
                            }
                        </td>
                        <td>
                            <input type="number" step="0.01" class="form-control" @bind="_editModel!.UnitPrice" />
                            @if (_validationErrors.TryGetValue(nameof(Product.UnitPrice), out var priceErr))
                            {
                                <div class="text-danger small">@priceErr</div>
                            }
                        </td>
                        <td>
                            <select class="form-select" @bind="_editModel!.Category">
                                <option value="">-- Select --</option>
                                @foreach (var cat in Product.Categories)
                                {
                                    <option value="@cat">@cat</option>
                                }
                            </select>
                            @if (_validationErrors.TryGetValue(nameof(Product.Category), out var catErr))
                            {
                                <div class="text-danger small">@catErr</div>
                            }
                        </td>
                        <td>
                            <button class="btn btn-success btn-sm me-1" @onclick="SaveAsync">Save</button>
                            <button class="btn btn-secondary btn-sm" @onclick="Cancel">Cancel</button>
                        </td>
                    </tr>
                }
                else
                {
                    <tr>
                        <td>@product.Name</td>
                        <td>@product.Quantity</td>
                        <td>@product.UnitPrice.ToString("C")</td>
                        <td>@product.Category</td>
                        <td>
                            <button class="btn btn-primary btn-sm" @onclick="() => Edit(product)">Edit</button>
                        </td>
                    </tr>
                }
            }
        </tbody>
    </table>
}

@code {
    private List<Product>? _products;
    private int? _editingId;
    private Product? _editModel;
    private Dictionary<string, string> _validationErrors = new();

    protected override async Task OnInitializedAsync()
    {
        _products = await InventoryService.GetAllAsync();
    }

    private void Edit(Product product)
    {
        _editingId = product.Id;
        _editModel = new Product
        {
            Id = product.Id,
            Name = product.Name,
            Quantity = product.Quantity,
            UnitPrice = product.UnitPrice,
            Category = product.Category
        };
        _validationErrors.Clear();
    }

    private bool Validate()
    {
        _validationErrors.Clear();
        var context = new ValidationContext(_editModel!);
        var results = new List<ValidationResult>();

        if (!Validator.TryValidateObject(_editModel!, context, results, validateAllProperties: true))
        {
            foreach (var result in results)
            {
                foreach (var member in result.MemberNames)
                {
                    _validationErrors.TryAdd(member, result.ErrorMessage ?? "Invalid.");
                }
            }
        }

        return _validationErrors.Count == 0;
    }

    private async Task SaveAsync()
    {
        if (!Validate())
            return;

        await InventoryService.UpdateAsync(_editModel!);
        _products = await InventoryService.GetAllAsync();
        _editingId = null;
        _editModel = null;
    }

    private void Cancel()
    {
        _editingId = null;
        _editModel = null;
        _validationErrors.Clear();
    }
}

